2044 /// Calculates control-dependent range for the given def at the given context
2045 /// by looking at dominating conditions inside of the loop
2046 void WidenIV::calculatePostIncRange(Instruction *NarrowDef,
2047                                     Instruction *NarrowUser) {
2048   Value *NarrowDefLHS;
2049   const APInt *NarrowDefRHS;
2050   if (!match(NarrowDef, m_NSWAdd(m_Value(NarrowDefLHS),
2051                                  m_APInt(NarrowDefRHS))) ||
2052       !NarrowDefRHS->isNonNegative())
2053     return;
2054 
2055   auto UpdateRangeFromCondition = [&] (Value *Condition,
2056                                        bool TrueDest) {
2057     CmpInst::Predicate Pred;
2058     Value *CmpRHS;
2059     if (!match(Condition, m_ICmp(Pred, m_Specific(NarrowDefLHS),
2060                                  m_Value(CmpRHS))))
2061       return;
2062 
2063     CmpInst::Predicate P =
2064             TrueDest ? Pred : CmpInst::getInversePredicate(Pred);
2065 
2066     auto CmpRHSRange = SE->getSignedRange(SE->getSCEV(CmpRHS));
2067     auto CmpConstrainedLHSRange =
2068             ConstantRange::makeAllowedICmpRegion(P, CmpRHSRange);
2069     auto NarrowDefRange = CmpConstrainedLHSRange.addWithNoWrap(
2070         *NarrowDefRHS, OverflowingBinaryOperator::NoSignedWrap);
2071 
2072     updatePostIncRangeInfo(NarrowDef, NarrowUser, NarrowDefRange);
2073   };
2074 
2075   auto UpdateRangeFromGuards = [&](Instruction *Ctx) {
2076     if (!HasGuards)
2077       return;
2078 
2079     for (Instruction &I : make_range(Ctx->getIterator().getReverse(),
2080                                      Ctx->getParent()->rend())) {
2081       Value *C = nullptr;
2082       if (match(&I, m_Intrinsic<Intrinsic::experimental_guard>(m_Value(C))))
2083         UpdateRangeFromCondition(C, /*TrueDest=*/true);
2084     }
2085   };
2086 
2087   UpdateRangeFromGuards(NarrowUser);
2088 
2089   BasicBlock *NarrowUserBB = NarrowUser->getParent();
2090   // If NarrowUserBB is statically unreachable asking dominator queries may
2091   // yield surprising results. (e.g. the block may not have a dom tree node)
2092   if (!DT->isReachableFromEntry(NarrowUserBB))
2093     return;
2094 
2095   for (auto *DTB = (*DT)[NarrowUserBB]->getIDom();
2096        L->contains(DTB->getBlock());
2097        DTB = DTB->getIDom()) {
2098     auto *BB = DTB->getBlock();
2099     auto *TI = BB->getTerminator();
2100     UpdateRangeFromGuards(TI);
2101 
2102     auto *BI = dyn_cast<BranchInst>(TI);
2103     if (!BI || !BI->isConditional())
2104       continue;
2105 
2106     auto *TrueSuccessor = BI->getSuccessor(0);
2107     auto *FalseSuccessor = BI->getSuccessor(1);
2108 
2109     auto DominatesNarrowUser = [this, NarrowUser] (BasicBlockEdge BBE) {
2110       return BBE.isSingleEdge() &&
2111              DT->dominates(BBE, NarrowUser->getParent());
2112     };
2113 
2114     if (DominatesNarrowUser(BasicBlockEdge(BB, TrueSuccessor)))
2115       UpdateRangeFromCondition(BI->getCondition(), /*TrueDest=*/true);
2116 
2117     if (DominatesNarrowUser(BasicBlockEdge(BB, FalseSuccessor)))
2118       UpdateRangeFromCondition(BI->getCondition(), /*TrueDest=*/false);
2119   }
2120 }
