1566       OpCode != Instruction::Mul)
1567     return false;
1568 
1569   // The operand that is not defined by NarrowDef of DU. Let's call it the
1570   // other operand.
1571   assert((NarrowUse->getOperand(0) == NarrowDef ||
1572           NarrowUse->getOperand(1) == NarrowDef) &&
1573          "bad DU");
